import { Component } from '@angular/core';
import { RouterLink } from '@angular/router';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [RouterLink],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent {
  banners = [
    {
      date: '08 septembre 2022',
      title: 'Lancement officiel du Logiciel de Gestion Intégrée des Droits, Taxes et Redevances « LOGIRAD »',
      subtitle: 'Cérémonie présidée par le Premier Ministre pour marquer le démarrage officiel de la plateforme.',
      badge: 'LOGIRAD'
    },
    {
      date: '19 septembre – 21 décembre 2022',
      title: 'Formation de 1 080 utilisateurs dans les provinces du Sud et de l’Est',
      subtitle:
        'Agents de la DGM, Mines, Hydrocarbures, PTNTIC, Affaires foncières et Environnement formés à l’utilisation de LOGIRAD.',
      badge: 'Formation'
    },
    {
      date: '29 décembre 2022',
      title: 'Circulaire ministérielle n°003 sur l’utilisation obligatoire de LOGIRAD',
      subtitle:
        'Mesures d’encadrement de la procédure dématérialisée pour optimiser la mobilisation des recettes non fiscales.',
      badge: 'Texte réglementaire'
    }
  ];

  stats = [
    { value: '+4 250', label: 'Utilisateurs formés' },
    { value: '+2 500', label: 'Utilisateurs connectés' },
    { value: '26', label: 'Provinces' },
    { value: '2', label: 'Vagues lancées' }
  ];

  supportCards = [
    {
      title: 'Obtenir les accès',
      description:
        'Contactez-nous pour obtenir un identifiant et un mot de passe afin de travailler dans LOGIRAD.',
      icon: '🔐'
    },
    {
      title: 'Dysfonctionnement',
      description:
        'Signalez tout dysfonctionnement ou problème technique de la plateforme à notre équipe de support.',
      icon: '🛟'
    },
    {
      title: "Centre d'appel",
      description:
        'Pour toute urgence, appelez les numéros renseignés sur la page de contact de la DGRAD.',
      icon: '📞'
    },
    {
      title: 'Textes réglementaires',
      description:
        "Téléchargez les arrêtés, circulaires et autres textes encadrant l'utilisation de LOGIRAD.",
      icon: '📜'
    }
  ];

  assietteServices = ['Mines', 'Hydrocarbures', 'Affaires foncières', 'Environnement', 'PTNTIC & DGM'];

  provincesPhase1 =
    'Kinshasa, Kongo Central, Tshopo, Haut-Uélé, Bas-Uélé, Tanganyika, Haut-Katanga, Haut-Lomami, Lualaba';
  provincesPhase2 =
    'Kasaï, Kasaï Central, Kasaï Oriental, Lomami, Sankuru, Maniema, Sud-Kivu';

  newsItems = [
    {
      type: 'Atelier',
      title: 'Atelier d’évaluation de la plateforme LOGIRAD',
      date: ''
    },
    {
      type: 'Formation',
      title: 'Deuxième vague de formation LOGIRAD',
      date: ''
    },
    {
      type: 'Formation',
      title: 'Montée en compétence des agents de la DGRAD sur les nouvelles technologies',
      date: ''
    }
  ];
}
